from abc import ABC, abstractmethod

class StorageStrategy(ABC):
    @abstractmethod
    def save(self, data):
        pass

class FileStorage(StorageStrategy):
    def save(self, data):
        with open('storage.txt', 'w') as f:
            f.write(str(data))

class DatabaseStorage(StorageStrategy):
    def save(self, data):
        print(f'Saving to database: {data}')
